head.script:
//-------------------------------------------------------------------------
// PGM명 : 고객사 월별추이(NGLS) (co_404_01_55b)
// 작성자 : 송정희
// 최초작성일자 : 2026-12-15
//-------------------------------------------------------------------------
scwin.fromDate_YyMm = ""; // 작업날짜
scwin.fromDate_YyMm = WebSquare.date.getCurrentServerDate("yyyyMM");

scwin.onpageload = function() {
console.log("PGM : 고객사 월별추이(NGLS) (co_404_01_55b)");          
    const codeOptions = [
        { grpCd : "CO012", compID : "lc_unit"}     // 단위               
    ];
    $c.data.setCommonCode(codeOptions);

    ed_yyyy.setValue(scwin.fromDate_YyMm);		
	lc_deptClsCd.setValue("A");	// 부서-전체
};

//-------------------------------------------------------------------------
// Default Unit 을 설정
//-------------------------------------------------------------------------
scwin.ondataload = function() {      
	lc_unit.setSelectedIndex(2);	    // 백만원단위          
}

//-------------------------------------------							
// 그리드 높이 늘리고 줄이기							
//-------------------------------------------							
scwin.f_grdHeiht = function(gridNm, size) {							

    let strHeight = gridNm.style.height ;							
    let intHeight = parseInt(strHeight.replace("px",""));							
    intHeight = intHeight + size;							
    if (intHeight > 0 ) {						
        gridNm.style.height = intHeight + "px";							
    }							
}  

//-------------------------------------------------------------------------
// 엑셀 출력
//-------------------------------------------------------------------------
scwin.f_Excel = async function() {
   if(ds_master.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
        return;
    }
     cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (!cfrm) {
        return;
    }
    let gridColCount = 0;
    for(let i = 0; i < gr_master.getTotalCol(); i++){
        if(gr_master.getColumnVisible(i)==true){
            gridColCount++;
        }
    }

    let str = $c.gus.cfGetFormatStr(ed_yyyy.getValue().trim(), "####");

    let startRowIndex = 0;
    let infoArr = [{
        rowIndex : 0,             
        colIndex : 0,            
        colSpan : gridColCount,   
        rowSpan : 1,
        text : "고객사 월별추이(NGLS)",
        textAlign : "center",    
        fontSize : 12,
        drawBorder : false,       
        color : "black",          
        backgroundColor : "#ffffff" 
    },{
        rowIndex : 2,             
        colIndex : 0,           
        colSpan : gridColCount,  
        rowSpan : 1,
        text : "조회년도 ["+ str +"]",
        textAlign : "left",    
        fontSize : 10,
        drawBorder : false,       
        color : "black",       
        backgroundColor : "#ffffff" 
    }]

    const options = {
        fileName: "고객사 월별추이(NGLS)_"+str+".xlsx",
        sheetName: "고객사 월별추이(NGLS)_"+str ,
        startRowIndex : 3,        
        startColumnIndex : 0,
        type : 1
    };
    await $c.data.downloadGridViewExcel(gr_master, options, infoArr);
};

// 조회
scwin.f_Retrieve = async function() {
    // 조회조건 필수사항 체크
    if ( ed_yyyy.getValue().trim().length != 4 ) {
        await $c.win.alert("조회년도는 필수입력 입니다.");
        ed_yyyy.focus();
        return;
    }

    //if (await !$c.gus.cfValidate([ed_yyyy])) {
    //    return;
    //}
    dma_search.set("yyyy", ed_yyyy.getValue());
    dma_search.set("deptClsCd", lc_deptClsCd.getValue() );

    $c.sbm.execute(sbm_master);
}

//-------------------------------------------------------------------------
// 그리드의 단위를 변경한다.
//-------------------------------------------------------------------------
scwin.f_changeUnit = function () {
    scwin.cunit = 1;
    if (lc_unit.getValue() == "02") { scwin.cunit = 1000; }
    if (lc_unit.getValue() == "03") { scwin.cunit = 1000000; }
    if (lc_unit.getValue() == "04") { scwin.cunit = 100000000; }

    scwin.f_changeUnitAmt(scwin.cunit);   
}

//------------------------------------------------------------------------
// 그리드 컬럼의 금액단위를 정한다. 
//------------------------------------------------------------------------
scwin.f_changeUnitAmt = function(unitAmt) {
    var ds_master_rcnt = ds_master.getRowCount();      
    if (ds_master_rcnt == 0) {
        return;
    }

    const cols_co4040155b = ["saleCost01", "businessProfit01", "saleCost02", "businessProfit02", "saleCost03", "businessProfit03", "saleCost04", "businessProfit04"
                           , "saleCost05", "businessProfit05", "saleCost06", "businessProfit06", "saleCost07", "businessProfit07", "saleCost08", "businessProfit08"
                           , "saleCost09", "businessProfit09", "saleCost10", "businessProfit10", "saleCost11", "businessProfit11", "saleCost12", "businessProfit12"
                           , "saleCostTotal", "businessProfitTotal" ];

    const cols_avg = [ "saleCostAvg", "businessProfitAvg" ];

    var t_gridUnitAmt = 0;
    for (var i=0; i < ds_master_rcnt; i++) {
        for (var j=0; j < cols_co4040155b.length; j++) {
            t_gridUnitAmt = 0;  
                if ( $c.gus.cfIsNull(ds_master.getCellData(i, cols_co4040155b[j])) || !$c.num.isNumber(ds_master.getCellData(i, cols_co4040155b[j]))) { 
                    ds_master.setCellData(i, cols_co4040155b[j], 0); 
                } else { 
                    t_gridUnitAmt = $c.num.round($c.num.parseInt(ds_master.getCellData(i, cols_co4040155b[j])) / unitAmt, 0);    
                    ds_master.setCellData(i, cols_co4040155b[j], t_gridUnitAmt);
                }
        }
        for (var k=0; k < cols_avg.length; k++) {
            t_gridUnitAmt = 0;  
                if ( $c.gus.cfIsNull(ds_master.getCellData(i, cols_avg[k])) || !$c.num.isNumber(ds_master.getCellData(i, cols_avg[k]))) { 
                    ds_master.setCellData(i, cols_avg[k], 0); 
                } else { 
                    t_gridUnitAmt = $c.num.round($c.num.parseInt(ds_master.getCellData(i, cols_avg[k])), 0);    
                    ds_master.setCellData(i, cols_avg[k], t_gridUnitAmt);
                }
        }

    }            
}

scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.ds_master_ondataload = function () {
    var rowCnt = ds_master.getTotalRow();
    totalRows.setValue(rowCnt);    
    ds_master_cpy.removeAll();

	if( rowCnt == 0 ){
	    if( $c.gus.cfCheckCreateFlag() == true){
	    	$c.gus.cfTurnCreateFlag(false);
	    }else{
	 		$c.gus.cfAlertMsg(MSG_CM_WRN_002);
	    }
       return;
	}

    let orgData = ds_master.getAllJSON();
    ds_master_cpy.setJSON(orgData);

    scwin.f_grHiddenCols();     
    scwin.f_changeUnit();
};

scwin.lc_unit_onselected = function () {
    scwin.f_Retrieve();
};

scwin.f_grHiddenCols = function() {

}

scwin.footerF = function(aTotal, bTotal) {
    var vProfitRate = 0;
    if(bTotal == 0) {
        vProfitRate = 0;
    } else {
        vProfitRate = $c.num.round(aTotal * 100 / bTotal, 2);
    }
    return vProfitRate;
};
